\begin{algorithm}[H]
\caption{Batch Normalization}
\textbf{Input:} Values of $x$ over a mini-batch: $\mathcal{B} = \{x_1, ..., x_m\}$; Parameters to be learned: $\gamma$, $\beta$
\textbf{Output:} $\{y_i = \text{BN}_{\gamma, \beta}(x_i)\}$

\begin{align*}
\mu_{\mathcal{B}} &\leftarrow \frac{1}{m} \sum_{i=1}^{m} x_i && \text{// mini-batch mean} \\
\sigma_{\mathcal{B}}^2 &\leftarrow \frac{1}{m} \sum_{i=1}^{m} (x_i - \mu_{\mathcal{B}})^2 && \text{// mini-batch variance} \\
\widehat{x}_i &\leftarrow \frac{x_i - \mu_{\mathcal{B}}}{\sqrt{\sigma_{\mathcal{B}}^2 + \epsilon}} && \text{// normalize} \\
y_i &\leftarrow \gamma \widehat{x}_i + \beta \equiv \text{BN}_{\gamma, \beta}(x_i) && \text{// scale and shift}
\end{align*}
\end{algorithm}
```

